import{_ as n,C as o,o as l,c as s,E as r,w as a,a as t,a0 as g}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Bulgaria Legal Rights","description":"Legal rights for transgender people in Bulgaria","frontmatter":{"layout":"doc","title":"Bulgaria Legal Rights","description":"Legal rights for transgender people in Bulgaria"},"headers":[],"relativePath":"europe/bulgaria/legal-rights.md","filePath":"europe/bulgaria/legal-rights.md","lastUpdated":null}'),c={name:"europe/bulgaria/legal-rights.md"};function d(u,e,h,m,p,f){const i=o("Badge");return l(),s("div",null,[r(i,{variant:"red"},{default:a(()=>[...e[0]||(e[0]=[t("No Clear Legal Framework",-1)])]),_:1}),r(i,{variant:"red"},{default:a(()=>[...e[1]||(e[1]=[t("Court-Dependent Process",-1)])]),_:1}),r(i,{variant:"red"},{default:a(()=>[...e[2]||(e[2]=[t("Weak Anti-Discrimination",-1)])]),_:1}),e[3]||(e[3]=g('<h1 id="legal-rights-in-bulgaria" tabindex="-1">Legal Rights in Bulgaria <a class="header-anchor" href="#legal-rights-in-bulgaria" aria-label="Permalink to &quot;Legal Rights in Bulgaria&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>Bulgaria has <strong>no clear legal framework</strong> for gender recognition — it relies entirely on inconsistent court decisions:</p><ul><li><strong>Requirements</strong>: Psychiatric diagnosis of gender dysphoria is generally required, but courts have varied opinions</li><li><strong>No statutory procedure</strong>: There is no dedicated law governing gender recognition</li><li><strong>Process</strong>: Must file a court case — outcomes vary significantly by judge and region</li><li><strong>Surgery</strong>: Not explicitly required by law, but some judges demand it</li><li><strong>Age</strong>: 18+ only</li><li><strong>Outcome</strong>: Many cases are rejected; successful applicants report a years-long process</li></ul><h3 id="the-process" tabindex="-1">The Process <a class="header-anchor" href="#the-process" aria-label="Permalink to &quot;The Process&quot;">​</a></h3><ol><li>Diagnosis from a psychiatrist</li><li>Gather medical documentation</li><li>File a court case for gender marker change</li><li>Attend court hearings (may require multiple appearances)</li><li>If approved, update civil registry documents</li></ol><p><strong>Note</strong>: The lack of a clear legal framework means every case is a legal battle. The European Court of Human Rights has ruled against Bulgaria for failing to provide clear gender recognition procedures, but the government has not implemented reforms.</p><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><ul><li>Processed through the <strong>Civil Registry</strong> (Гражданска регистрация)</li><li>Requires justification — gender transition is accepted as a valid reason</li><li>Name change can sometimes be done separately from gender marker change</li><li>Processed within 1-3 months</li><li>Court involvement may be required if the registry refuses</li></ul><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><ul><li><strong>Employment</strong>: Prohibited under the Labour Code, but gender identity is not explicitly protected</li><li><strong>Goods and Services</strong>: General non-discrimination provisions under the Protection Against Discrimination Act</li><li><strong>Education</strong>: Limited protections</li><li><strong>Enforcement</strong>: The Commission for Protection Against Discrimination handles complaints but is not always effective</li></ul><p>The <strong>Protection Against Discrimination Act</strong> prohibits discrimination based on &quot;sexual orientation&quot; but does not explicitly include gender identity. Courts have inconsistently applied protections.</p><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><ul><li>The <strong>Criminal Code</strong> does not explicitly include gender identity in hate crime provisions</li><li>Sexual orientation is not explicitly covered either</li><li>No enhanced penalties for anti-trans hate crimes</li><li>Bulgaria has been criticized by the EU for failing to protect LGBTQ+ people from hate crimes</li></ul><h2 id="document-recognition" tabindex="-1">Document Recognition <a class="header-anchor" href="#document-recognition" aria-label="Permalink to &quot;Document Recognition&quot;">​</a></h2><ul><li>Updated documents are recognized internationally in principle</li><li>Many trans people report difficulties with border control and administrative authorities</li><li>Previous documents may be requested by authorities</li><li>Bulgarian IDs and passports reflect the gender marker from civil registry</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.bghelsinki.org/" target="_blank" rel="noreferrer">Bulgarian Helsinki Committee</a></li><li><a href="https://www.ilga-europe.org/country/bulgaria/" target="_blank" rel="noreferrer">ILGA-Europe - Bulgaria</a></li><li><a href="https://hudoc.echr.coe.int/" target="_blank" rel="noreferrer">European Court of Human Rights - Bulgaria Gender Recognition Cases</a></li></ul>',18))])}const v=n(c,[["render",d]]);export{y as __pageData,v as default};
